import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract BLSTToken is ERC20, Ownable {

    uint256 constant TOTAL_SUPPLY = 100_000_000 * 10**18; // 100 million tokens, with 18 decimal precision

    constructor() ERC20("BLSTToken", "BLST") {
